// Web Form Client Script — paste this into the Web Form's "Client Script" field
// Gates each signature field behind its "I have read and understood" checkbox

frappe.web_form.after_load = () => {
	toggle_signature("health_declaration_confirm", "health_signature");
	toggle_signature("nda_confirm", "nda_signature");
	toggle_signature("bgv_confirm", "bgv_signature");
};

frappe.web_form.on("health_declaration_confirm", (field, value) => {
	frappe.web_form.set_df_property("health_signature", "read_only", !value);
});

frappe.web_form.on("nda_confirm", (field, value) => {
	frappe.web_form.set_df_property("nda_signature", "read_only", !value);
});

frappe.web_form.on("bgv_confirm", (field, value) => {
	frappe.web_form.set_df_property("bgv_signature", "read_only", !value);
});

function toggle_signature(confirm_field, signature_field) {
	const checked = frappe.web_form.get_value(confirm_field);
	frappe.web_form.set_df_property(signature_field, "read_only", !checked);
}

frappe.ready(function() {
    function getCompanyValue() {
        if (typeof frappe.web_form !== 'undefined' && frappe.web_form.fields_dict) {
            let f = frappe.web_form.fields_dict['company'];
            return f ? f.get_value() : null;
        }
        if (typeof cur_frm !== 'undefined' && cur_frm) {
            return cur_frm.doc.company;
        }
        return null;
    }

    let replaced = false;

    function updateCompanyName() {
        if (replaced) return;
        let companyValue = getCompanyValue();
        if (!companyValue) return;

        frappe.call({
            method: "frappe.client.get_value",
            args: { doctype: "Company", filters: companyValue, fieldname: "company_name" },
            callback: function(r) {
                if (r.message && r.message.company_name) {
                    let block = document.getElementById('agreement-html-block');
                    if (block) {
                        block.innerHTML = block.innerHTML.replaceAll('{{COMPANY_NAME}}', r.message.company_name.toUpperCase());
                        replaced = true;
                    }
                }
            }
        });
    }

    // Poll every 1s for up to 20s, in case the field isn't filled/committed yet when page loads
    let pollCount = 0;
    let poller = setInterval(function() {
        pollCount++;
        updateCompanyName();
        if (replaced || pollCount > 20) clearInterval(poller);
    }, 1000);

    // Also bind to change/blur events for instant response once available
    setTimeout(function() {
        if (typeof frappe.web_form !== 'undefined' && frappe.web_form.fields_dict) {
            let companyField = frappe.web_form.fields_dict['company'];
            if (companyField && companyField.$input) {
                companyField.$input.on('change blur awesomplete-selectcomplete', updateCompanyName);
            }
        }
    }, 500);
});

frappe.ready(function() {
    var params = new URLSearchParams(window.location.search);
    var applicant_name = params.get('applicant_name');
    var email = params.get('email');
    var phone = params.get('phone');
    var job_applicant = params.get('job_applicant');

    // Set the name field to link to existing Job Applicant
    if (job_applicant) {
        frappe.web_form.doc.name = decodeURIComponent(job_applicant);
    }

    function fill_fields() {
        if (applicant_name) {
            frappe.web_form.set_value('applicant_name', decodeURIComponent(applicant_name));
        }
        if (email) {
            frappe.web_form.set_value('email_id', decodeURIComponent(email));
        }
        if (phone) {
            frappe.web_form.set_value('phone_number', decodeURIComponent(phone));
        }
    }

    setTimeout(fill_fields, 500);
    setTimeout(fill_fields, 1500);
});
